fn init_registry(state: &mut LuaState) -> Result<(), LuaError> {
    // C: Table *registry = luaH_new(L);
    // macros.tsv: luaH_new → state.new_table()
    let registry = state.new_table();

    // C: sethvalue(L, &g->l_registry, registry);
