201	        (LuaValue::Bool(x), LuaValue::Bool(y)) => x == y,
202	        (LuaValue::Int(x), LuaValue::Int(y)) => x == y,
203	        (LuaValue::Float(x), LuaValue::Float(y)) => x == y,
204	        (LuaValue::Int(i), LuaValue::Float(f)) | (LuaValue::Float(f), LuaValue::Int(i)) => *f == *i as f64,
205	        (LuaValue::Str(x), LuaValue::Str(y)) => x.as_bytes() == y.as_bytes(),
206	        (LuaValue::Table(x), LuaValue::Table(y)) => GcRef::ptr_eq(x, y),
207	        (LuaValue::UserData(x), LuaValue::UserData(y)) => GcRef::ptr_eq(x, y),
