/// C: `static int math_deg(lua_State *L)`
fn math_deg(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: lua_pushnumber(L, luaL_checknumber(L, 1) * (180.0 / PI));
    let x = state.check_number(1)?;
    state.push(LuaValue::Float(x * (180.0 / PI)));
    Ok(1)
