/// C: `static int math_rad(lua_State *L)`
fn math_rad(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: lua_pushnumber(L, luaL_checknumber(L, 1) * (PI / 180.0));
    let x = state.check_number(1)?;
    state.push(LuaValue::Float(x * (PI / 180.0)));
    Ok(1)
